-- KPI Data Table
-- This table stores KPI metrics for tracking Gross Ads (GA), 
-- Unique Active Outlets (UAO), and New Outlets (NA) by branch and zone

CREATE TABLE IF NOT EXISTS kpi_data (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  branch VARCHAR(255) NOT NULL,
  zone VARCHAR(255) NOT NULL,
  month VARCHAR(7) NOT NULL, -- Format: YYYY-MM (e.g., 2024-01)
  year INTEGER NOT NULL,
  
  -- Gross Ads (GA)
  ga NUMERIC(10,2) DEFAULT 0,
  ga_target NUMERIC(10,2) DEFAULT 0,
  
  -- Unique Active Outlets (UAO)
  uao NUMERIC(10,2) DEFAULT 0,
  uao_target NUMERIC(10,2) DEFAULT 0,
  
  -- New Outlets (NA)
  na NUMERIC(10,2) DEFAULT 0,
  na_target NUMERIC(10,2) DEFAULT 0,
  
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW(),
  
  -- Unique constraint to prevent duplicate entries
  UNIQUE(branch, zone, month, year)
);

-- Create index for faster queries
CREATE INDEX IF NOT EXISTS idx_kpi_data_branch_year ON kpi_data(branch, year);
CREATE INDEX IF NOT EXISTS idx_kpi_data_branch_zone_year ON kpi_data(branch, zone, year);
CREATE INDEX IF NOT EXISTS idx_kpi_data_year ON kpi_data(year);

ON CONFLICT (branch, zone, month, year) DO UPDATE SET
  ga = EXCLUDED.ga,
  ga_target = EXCLUDED.ga_target,
  uao = EXCLUDED.uao,
  uao_target = EXCLUDED.uao_target,
  na = EXCLUDED.na,
  na_target = EXCLUDED.na_target,
  updated_at = NOW();
